#include <bits/stdc++.h>
using namespace std;

const int N = 100005;
const int MOD = 1e8 - 3;

int n;
int a[N], b[N];
int c[N], d[N];
int bit[N];

void add(int i, int x) {
    while (i <= n) {
        bit[i] += x;
        i += i & -i;
    }
}

int sum(int i) {
    int res = 0;
    while (i > 0) {
        res += bit[i];
        i -= i & -i;
    }
    return res;
}

int main() {
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        scanf("%d", &a[i]);
        c[i] = a[i];
    }

    for (int i = 1; i <= n; i++) {
        scanf("%d", &b[i]);
        d[i] = b[i];
    }

    sort(c + 1, c + n + 1);
    sort(d + 1, d + n + 1);

    for (int i = 1; i <= n; i++) {
        a[i] = lower_bound(c + 1, c + n + 1, a[i]) - c;
        b[i] = lower_bound(d + 1, d + n + 1, b[i]) - d;
    }

    int pos[N];
    for (int i = 1; i <= n; i++) {
        pos[a[i]] = i;
    }

    for (int i = 1; i <= n; i++) {
        b[i] = pos[b[i]];
    }

    long long ans = 0;
    for (int i = 1; i <= n; i++) {
        add(b[i], 1);
        ans += i - sum(b[i]);
    }

    printf("%lld\n", ans % MOD);

    return 0;
}
